#!/bin/bash

set -euo pipefail

source .venv/bin/activate

# Per-apply runtime dir on tmpfs. Falls back to /tmp on macOS / CI where
# XDG_RUNTIME_DIR is unset.
runtime_dir="${XDG_RUNTIME_DIR:-/tmp}"
work_dir=$(mktemp -d "$runtime_dir/k8s-modules.XXXXXXXX")
chmod 700 "$work_dir"

trap 'ssh-agent -k >/dev/null 2>&1 || true; rm -rf "$work_dir"' EXIT

# Per-apply ssh-agent. The cluster SSH key is generated by Terraform and piped
# directly into this agent (see modules/provision_hetzner_server), so the key
# never lands on disk.
eval "$(ssh-agent -s -a "$work_dir/agent.sock")" >/dev/null

# Per-apply known_hosts file. StrictHostKeyChecking=accept-new (set on each
# ansible_playbook via ansible_ssh_common_args) records the host key on first
# connect and re-verifies it for the rest of the apply, with no pollution of
# ~/.ssh/known_hosts and no MITM window past the first connect.
export TF_VAR_known_hosts_file="$work_dir/known_hosts"
: >"$TF_VAR_known_hosts_file"
chmod 600 "$TF_VAR_known_hosts_file"

terraform plan -out=tfplan
terraform apply -auto-approve tfplan
